import sys
from itertools import combinations

def solve_length(n_str, digits):
    # Find smallest number of same length as n_str using only chars in digits, >= n_str
    L = len(n_str)
    digits = sorted(digits)

    # Greedy with backtracking
    result = [''] * L

    def backtrack(pos, tight):
        if pos == L:
            return True
        lo = n_str[pos] if tight else '0'
        # Try digits >= lo
        for d in digits:
            if pos == 0 and d == '0' and L > 1:
                continue
            if d < lo:
                continue
            result[pos] = d
            new_tight = tight and (d == lo)
            if new_tight:
                if backtrack(pos + 1, True):
                    return True
            else:
                # Fill rest with smallest digit
                for i in range(pos + 1, L):
                    result[i] = digits[0]
                return True
        return False

    if backtrack(0, True):
        return ''.join(result)
    return None

def smallest_geq(n_str, digits):
    digits = sorted(set(digits))
    L = len(n_str)

    result = solve_length(n_str, digits)
    if result is not None:
        return int(result)

    # Try length L+1
    non_zero = [d for d in digits if d != '0']
    if not non_zero:
        return None

    return int(non_zero[0] + digits[0] * L)

def solve(n, k):
    n_str = str(n)
    best = None

    all_digits = [str(i) for i in range(10)]

    for combo in combinations(all_digits, k):
        digits = list(combo)
        # Also try subsets (size 1 if k=2)
        res = smallest_geq(n_str, digits)
        if res is not None:
            if best is None or res < best:
                best = res

    # Also try size 1 subsets when k=2
    if k >= 1:
        for d in all_digits:
            res = smallest_geq(n_str, [d])
            if res is not None:
                if best is None or res < best:
                    best = res

    return best

input_data = sys.stdin.read().split()
t = int(input_data[0])
idx = 1
results = []
for _ in range(t):
    n = int(input_data[idx]); k = int(input_data[idx+1])
    idx += 2
    results.append(str(solve(n, k)))

print('\n'.join(results))
